(function applyEnglishProductCopy() {
  const englishMap = window.GCSOFA_PRODUCT_COPY_MAP_EN || {};
  const originalGetProducts = window.getProducts || getProducts;
  const originalFindProduct = window.findProduct || findProduct;

  function getProductKey(product = {}) {
    const values = [product.id, product.name, product.code, product.sku].filter(Boolean).join(' ');
    const match = values.match(/(?:GC[-_\s]*S)?(\d{4})/i);
    return match ? match[1] : '';
  }

  function mergeEnglishCopy(product) {
    const key = getProductKey(product);
    const copy = englishMap[key];
    if (!copy) return product;
    return {
      ...product,
      ...copy,
      id: product.id,
      image: product.image,
      introImages: product.introImages,
      extraIntroImages: product.extraIntroImages,
      createdAt: product.createdAt,
      sortOrder: product.sortOrder,
      costSheet: product.costSheet,
      costRows: product.costRows,
      productionRows: product.productionRows,
      internalNotes: product.internalNotes,
    };
  }

  window.getProducts = function getEnglishProducts() {
    return originalGetProducts().map(mergeEnglishCopy);
  };

  window.findProduct = function findEnglishProductById(id) {
    const product = originalFindProduct(id);
    return product ? mergeEnglishCopy(product) : window.getProducts().find((item) => item.id === id);
  };
})();
